func atomic_notify[T uint32 | int64](mem []byte, addr T, count int32, waiters *sync.Map) int32 {
	_ = atomic_ptr32(mem, addr)

	if waiters == nil {
		return 0
	}
	wa, ok := waiters.Load(int64(addr))
	if !ok {
		return 0
	}

	w := wa.(*atomic_waiters)
	w.Lock()

	var res uint32
	for res < uint32(count) && w.N > 0 {
		w.C <- struct{}{}
		w.N--
		res++
	}

	w.Unlock()
	return int32(res)
}

func atomic_wait32[T uint32 | int64](mem []byte, addr T, exp uint32, timeout int64, waiters *sync.Map) int32 {
	const (
		ok        = 0
		not_equal = 1
		timed_out = 2
	)

	ptr := atomic_ptr32(mem, addr)
	if waiters == nil {
		panic("expected shared memory")
	}
	if big {
		exp = bits.ReverseBytes32(exp)
	}
	if timeout == 0 {
		if exp != atomic.LoadUint32(ptr) {
			return not_equal
		}
		return timed_out
	}

	wa, _ := waiters.LoadOrStore(int64(addr), &atomic_waiters{})
	w := wa.(*atomic_waiters)
	w.Lock()

	switch {
	case exp != atomic.LoadUint32(ptr):
		w.Unlock()
		return not_equal
	case w.C == nil:
		w.C = make(chan struct{}, min(math.MaxInt, math.MaxUint32))
	case w.N >= cap(w.C):
		w.Unlock()
		panic("too many waiters")
	}

	wait := w.C
	w.N++
	w.Unlock()

	if timeout < 0 {
		<-wait
		return ok
	}

	timer := time.NewTimer(time.Duration(timeout))
	select {
	case <-wait:
		timer.Stop()
		return ok
	case <-timer.C:
	}

	w.Lock()
	select {
	case <-wait:
		w.Unlock()
		return ok
	default:
		w.N--
		w.Unlock()
		return timed_out
	}
}

//go:nosplit
func atomic_ptr8[T uint32 | int64](mem []byte, addr T) (ptr *uint32, shift uint32) {
	ptr = (*uint32)(unsafe.Pointer((*[4]byte)(mem[addr&^3:])))
	shift = uint32(addr) & 3 * 8
	return
}

//go:nosplit
func atomic_ptr32[T uint32 | int64](mem []byte, addr T) *uint32 {
	if uint32(addr)&3 != 0 {
		panic("unaligned atomic")
	}
	return (*uint32)(unsafe.Pointer((*[4]byte)(mem[addr:])))
}

//go:nosplit
func atomic_ptr64[T uint32 | int64](mem []byte, addr T) *uint64 {
	if uint32(addr)&7 != 0 {
		panic("unaligned atomic")
	}
	return (*uint64)(unsafe.Pointer((*[8]byte)(mem[addr:])))
}

type atomic_waiters = struct {
	C chan struct{} // +checklocks:Mutex
	N int           // +checklocks:Mutex
	sync.Mutex
}

//go:nosplit
func i32(x int32) int32 { return x }

//go:nosplit
func i64(x int64) int64 { return x }

//go:nosplit
func i32_div_s(x, y int32) int32 {
	if y == -1 && x == math.MinInt32 {
		panic("integer overflow")
	}
	return x / y
}

//go:nosplit
func i64_div_s(x, y int64) int64 {
	if y == -1 && x == math.MinInt64 {
		panic("integer overflow")
	}
	return x / y
}

//go:nosplit
func i32_shl(x, y int32) int32 {
	return x << (y & 31)
}

//go:nosplit
func i32_shr_u(x, y int32) int32 {
	return int32(uint32(x) >> (y & 31))
}

//go:nosplit
func i64_shl(x, y int64) int64 {
	return x << (y & 63)
}

//go:nosplit
func i64_shr_u(x, y int64) int64 {
	return int64(uint64(x) >> (y & 63))
}

//go:nosplit
func i32_rotl(x, y int32) int32 {
	return int32(bits.RotateLeft32(uint32(x), int(y)))
}

//go:nosplit
func i32_trunc_f64_s(f float64) int32 {
	x := math.Trunc(f)
	switch {
	case f != f:
		panic("invalid conversion to integer")
	case x < math.MinInt32 || x > math.MaxInt32:
		panic("integer overflow")
	}
	return int32(x)
}

//go:nosplit
func i32_trunc_f64_u(f float64) int32 {
	x := math.Trunc(f)
	switch {
	case f != f:
		panic("invalid conversion to integer")
	case x < 0 || x > math.MaxUint32:
		panic("integer overflow")
	}
	return int32(uint32(x))
}

//go:nosplit
func i64_trunc_f64_u(f float64) int64 {
	x := math.Trunc(f)
	switch {
	case f != f:
		panic("invalid conversion to integer")
	case x < 0 || x >= math.MaxUint64:
		panic("integer overflow")
	}
	return int64(uint64(x))
}

func memory_init[T uint32 | uint64](mem []byte, data string, dest T, src, n uint32) {
	x := uint(min(uint64(dest), math.MaxUint))
	z := uint(src)
	y := x + uint(n)
	w := z + uint(n)
	copy(mem[x:y], data[z:w])
}

func memory_copy[T uint32 | uint64](mem []byte, dest, src, n T) {
	x := uint(min(uint64(dest), math.MaxUint))
	z := uint(min(uint64(src), math.MaxUint))
	c := uint(min(uint64(n), math.MaxUint))
	y := x + c
	w := z + c
	copy(mem[x:y], mem[z:w])
}

func memory_fill[T uint32 | uint64](mem []byte, dest T, val int32, n T) {
	x := uint(min(uint64(dest), math.MaxUint))
	y := x + uint(min(uint64(n), math.MaxUint))
	buf := mem[x:y]
	if len(buf) > 0 {
		buf[0] = byte(val)
		for i := 1; i < len(buf); {
			chunk := min(i, 8192)
			i += copy(buf[i:], buf[:chunk])
		}
	}
}

func memory_zero[T uint32 | uint64](mem []byte, dest, n T) {
	x := uint(min(uint64(dest), math.MaxUint))
	y := x + uint(min(uint64(n), math.MaxUint))
	clear(mem[x:y])
}

